// --- Architecture Note ---
// This component is built on LiveKit, a production-grade WebRTC service.
// This provides superior connection reliability, scalability, and simpler client logic
// compared to a pure Peer-to-Peer implementation with PeerJS.

// --- Configuration ---
const LIVEKIT_URL = 'wss://chatroom-8kj4411s.livekit.cloud';
const isScreenShareSupported = !!(navigator.mediaDevices && navigator.mediaDevices.getDisplayMedia);

// --- State Management with Reducer ---
type CallState = {
  connectionState: ConnectionState;
  isMuted: boolean;
  isVideoEnabled: boolean;
  isScreenSharing: boolean;
  remoteVideoTrack: Track | null;
};

type Action =
  | { type: 'SET_CONNECTION_STATE'; payload: ConnectionState }
  | { type: 'SET_REMOTE_TRACK'; payload: Track | null }
  | { type: 'TOGGLE_MUTE' }
  | { type: 'TOGGLE_VIDEO' }
  | { type: 'SET_SCREEN_SHARE'; payload: boolean };

const initialState: CallState = {
  connectionState: ConnectionState.Disconnected,
  isMuted: false,
  isVideoEnabled: true,
  isScreenSharing: false,
  remoteVideoTrack: null,
};

function callReducer(state: CallState, action: Action): CallState {
  switch (action.type) {
    case 'SET_CONNECTION_STATE':
      return { ...state, connectionState: action.payload };
    case 'SET_REMOTE_TRACK':
      return { ...state, remoteVideoTrack: action.payload };
    case 'TOGGLE_MUTE':
      return { ...state, isMuted: !state.isMuted };
    case 'TOGGLE_VIDEO':
      return { ...state, isVideoEnabled: !state.isVideoEnabled };
    case 'SET_SCREEN_SHARE':
